verbs.source:
verb :look() rxd {
  return { id: this, title: this.name, description: this.description, api_version: this.api_version, tools: ["inspect(id, opts?)", "search(query, opts?)", "create(parent, opts?)", "chparent(id, parent, opts?)", "recycle(id, opts?)", "set_property(id, name, value, opts?)"] };
}

verb :inspect(id, opts) rxd {
  // Structure/data view: owner, flags, parent, children, instances, location,
  // contents, and property summaries. No source output.
  return builder_inspect(id, opts);
}

verb :search(query, opts) rxd {
  // Bounded actor-scoped search across object names and property channels.
  // Source channels are reserved for the programmer surface.
  return builder_search(query, opts);
}

verb :create(parent, opts) rxd {
  // Creates an object owned by the invoking actor. There is intentionally no
  // owner option on the builder surface; creating for another actor is wizard
  // administration, not delegated building.
  let result = builder_create_object(parent, opts);
  observe({ type: "builder_created", actor: actor, id: result["id"], parent: parent, ts: now() });
  return result;
}

verb :chparent(id, parent, opts) rxd {
  let result = builder_chparent(id, parent, opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "builder_chparented", actor: actor, id: id, parent: parent, ts: now() });
  }
  return result;
}

verb :recycle(id, opts) rxd {
  let result = builder_recycle(id, opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "builder_recycled", actor: actor, id: id, ts: now() });
  }
  return result;
}

verb :set_property(id, name, value, opts) rxd {
  // Ordinary data value setting. This does not change verb source, property
  // perms, executable metadata, wizard/programmer flags, or ownership.
  return builder_set_property(id, name, value, opts);
}

verb :look() rxd {
  return { id: this, title: this.name, description: this.description, api_version: this.api_version, tools: ["inspect(id, opts?)", "resolve_verb(id, descriptor)", "list_verb(id, descriptor, opts?)", "search(query, opts?)", "install_verb(id, descriptor, source, opts?)", "set_verb_info(id, descriptor, opts?)", "set_property_info(id, name, opts?)", "edit_verb(id, descriptor, opts?)", "trace(id, descriptor, opts?)", "force_recycle(id, opts?)  [wizard-only]"] };
}

verb :inspect(id, opts) rxd {
  // Source-aware call-tree view with read filters: parent/features walk, own
  // and inherited verbs/properties, slots, impact hints, and optional readable
  // source summaries. No bytecode.
  return programmer_inspect(id, opts);
}

verb :resolve_verb(id, descriptor) rxd {
  return programmer_resolve_verb(id, descriptor);
}

verb :list_verb(id, descriptor, opts) rxd {
  // Return readable source and metadata for one ordered verb slot. This is
  // source-level only: no bytecode, opcode, literal-pool, or VM detail.
  return programmer_list_verb(id, descriptor, opts);
}

verb :search(query, opts) rxd {
  // Bounded actor-scoped search. opts.channels may include readable
  // verb_source; unreadable source is omitted, not summarized.
  return programmer_search(query, opts);
}

verb :install_verb(id, descriptor, source, opts) rxd {
  // Check and install source. opts.dry_run=true exercises the exact install
  // path, including authority, slot resolution, expected_version, mode, and
  // header diagnostics, but mutates nothing and emits no install observation.
  // opts.perms is rejected; the source header is canonical.
  let result = programmer_install_verb(id, descriptor, source, opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "programmer_installed", actor: actor, id: id, verb: descriptor, slot: result["slot"], version: result["version"], ts: now() });
  } else if (!result["ok"]) {
    observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: result["diagnostics"], dry_run: result["dry_run"], ts: now() });
  }
  return result;
}

verb :set_verb_info(id, descriptor, opts) rxd {
  // Metadata-only edit for aliases, arg spec, exposure flags, and perms.
  // Permission bits are changed here, not through source install. Does not
  // reinstall source. opts.dry_run=true validates without mutation.
  let result = programmer_set_verb_info(id, descriptor, opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "programmer_verb_info_changed", actor: actor, id: id, verb: descriptor, slot: result["slot"], version: result["version"], ts: now() });
  }
  return result;
}

verb :set_property_info(id, name, opts) rxd {
  // Define/update property metadata, defaults, perms, and type hints. This is
  // programmer authority, not the builder value-setting surface.
  return programmer_set_property_info(id, name, opts);
}

verb :edit_verb(id, descriptor, opts) rxd {
  // Door into this catalog's seeded $verb_editor instance. The editor room
  // owns the buffer session after this point; the target object stays where it is.
  return editor_invoke("the_verb_editor", id, descriptor, opts);
}

verb :trace(id, verb_name, opts) rxd {
  // Capture source-span traces for the next N invocations. v1.1.
  return programmer_trace(id, verb_name, opts);
}

verb :force_recycle(id, opts) rxd {
  // Wizard-only force_recycle. Bypasses most §RC6 reserved-list checks
  // (universal classes other than $system/$root/$nowhere; live actors,
  // whose sessions are terminated as part of the call). The engine
  // builtin raises E_PERM for non-wizards; non-wizard programmers see
  // this verb in tools listings but cannot call it. Audited as a
  // wiz_force_recycle wizard_action; emits a wiz_force_recycle
  // observation. Use sparingly — for irreversible world-teardown and
  // migration only.
  return wiz_force_recycle(id, opts);
}

verb :look() rxd {
  return { id: this, title: this.name, description: this.description, tools: ["what()", "view(opts?)", "replace(text)", "insert(line, text)", "delete(start, end?)", "dry_run()", "save()", "pause()", "abort()"] };
}

verb :what() rxd {
  return editor_what();
}

verb :view(opts) rxd {
  return editor_view(opts);
}

verb :replace(text) rxd {
  return editor_replace(text);
}

verb :insert(line, text) rxd {
  return editor_insert(line, text);
}

verb :delete(start, end) rxd {
  return editor_delete(start, end);
}

verb :dry_run() rxd {
  return editor_dry_run();
}

verb :save() rxd {
  return editor_save();
}

verb :pause() rxd {
  return editor_pause();
}

verb :abort() rxd {
  return editor_abort();
}
